ided name\", \"parameters\": {\"type\": \"object\", \"properties\": {\"name\": {\"type\": \"string\", \"description\": \"Name of the Pod\"}, \"namespace\": {\"type\": \"string\", \"description\": \"Namespace to get the Pod from\"}}, \"required\": [\"name\"]}}}, {\"type\": \"function\", \"function\": {\"name\": \"pods_list\", \"description\": \"List all the Kubernetes pods in the current cluster from all namespaces\", \"parameters\": {\"type\": \"object\", \"properties\": {\"fieldSelector\": {\"type\": \"string\", \"description\": \"Optional Kubernetes field selector to filter pods by field values (e.g. 'status.phase=Running', 'spec.nodeName=node1'). Supported fields: metadata.name, metadata.namespace, spec.nodeName, spec.restartPolicy, spec.schedulerName, spec.serviceAccountName, status.phase (Pending/Running/Succeeded/Failed/Unknown), status.podIP, status.nominatedNodeName. Note: CrashLoopBackOff is a container state, not a pod phase, so it cannot be filtered directly. See https://kubernetes.io/docs/concepts/overview/working-with-objects/field-selectors/\", \"pattern\": \"^[.\\\\-A-Za-z0-9]+([=!,]{1,2}[.\\\\-A-Za-z0-9]+)+$\"}, \"labelSelector\": {\"type\": \"string\", \"description\": \"Optional Kubernetes label selector (e.g. 'app=myapp,env=prod' or 'app in (myapp,yourapp)'), use this option when you want to filter the pods by label\", \"pattern\": \"^([/_.\\\\-A-Za-z0-9=, ()!])+$\"}}}}}, {\"type\": \"function\", \"function\": {\"name\": \"pods_list_in_namespace\", \"description\": \"List all the Kubernetes pods in the specified namespace in the current cluster\", \"parameters\": {\"type\": \"object\", \"properties\": {\"fieldSelector\": {\"type\": \"string\", \"description\": \"Optional Kubernetes field selector to filter pods by field values (e.g. 'status.phase=Running', 'spec.nodeName=node1'). Supported fields: metadata.name, metadata.namespace, spec.nodeName, spec.restartPolicy, spec.schedulerName, spec.serviceAccountName, status.phase (Pending/Running/Succeed